import { describe, it, expect } from 'vitest';
import { computeLinkCurvature, CurvatureLink } from '../../../../src/webview/components/graph/model/link/curvature';

function makeLink(source: string, target: string): CurvatureLink {
  return { source, target };
}

describe('computeLinkCurvature', () => {
  it('does nothing for empty array', () => {
    const links: CurvatureLink[] = [];
    computeLinkCurvature(links);
    expect(links).toEqual([]);
  });

  it('leaves single link between two nodes unchanged (no curvature set)', () => {
    const links = [makeLink('A', 'B')];
    computeLinkCurvature(links);
    expect(links[0].curvature).toBeUndefined();
  });

  it('assigns curvature for two links between same nodes (opposite directions)', () => {
    const links = [makeLink('A', 'B'), makeLink('B', 'A')];
    computeLinkCurvature(links);
    // Both should have curvature set (visual distinction comes from swapped source/target)
    expect(links[0].curvature).toBeDefined();
    expect(links[1].curvature).toBeDefined();
    expect(links[0].curvature).toBe(0.5);
    expect(links[1].curvature).toBe(0.5);
  });

  it('assigns distinct curvatures for two links in same direction', () => {
    const links = [makeLink('A', 'B'), makeLink('A', 'B')];
    computeLinkCurvature(links);
    expect(links[0].curvature).toBeDefined();
    expect(links[1].curvature).toBeDefined();
    expect(links[0].curvature).not.toBe(links[1].curvature);
  });

  it('keeps different curvature groups straight even when they share the same node pair', () => {
    const links: CurvatureLink[] = [
      { source: 'A', target: 'B', curvatureGroupId: 'import' },
      { source: 'A', target: 'B', curvatureGroupId: 'call' },
    ];

    computeLinkCurvature(links);

    expect(links[0].curvature).toBeUndefined();
    expect(links[1].curvature).toBeUndefined();
  });

  it('distributes curvatures evenly for 3+ parallel links', () => {
    const links = [makeLink('A', 'B'), makeLink('A', 'B'), makeLink('A', 'B')];
    computeLinkCurvature(links);
    const curvatures = links.map(link => link.curvature);
    // All should be defined
    expect(curvatures.every(cv => cv !== undefined)).toBe(true);
    // Should be evenly distributed and distinct
    const unique = new Set(curvatures);
    expect(unique.size).toBe(3);
  });

  it('assigns positive curvature (0.5 to 1) for self-loops', () => {
    const links = [makeLink('A', 'A'), makeLink('A', 'A')];
    computeLinkCurvature(links);
    for (const link of links) {
      expect(link.curvature).toBeGreaterThanOrEqual(0.5);
      expect(link.curvature).toBeLessThanOrEqual(1);
    }
  });

  it('single self-loop gets curvature 1', () => {
    const links = [makeLink('A', 'A')];
    computeLinkCurvature(links);
    expect(links[0].curvature).toBe(1);
  });

  it('works with object-style source/target (resolved nodes)', () => {
    const links: CurvatureLink[] = [
      { source: { id: 'A' }, target: { id: 'B' } },
      { source: { id: 'B' }, target: { id: 'A' } },
    ];
    computeLinkCurvature(links);
    expect(links[0].curvature).toBeDefined();
    expect(links[1].curvature).toBeDefined();
  });

  it('does not set curvature on single-link pairs among multi-link groups', () => {
    const links = [
      makeLink('A', 'B'),
      makeLink('A', 'B'),
      makeLink('C', 'D'), // single link, should stay undefined
    ];
    computeLinkCurvature(links);
    expect(links[0].curvature).toBeDefined();
    expect(links[1].curvature).toBeDefined();
    expect(links[2].curvature).toBeUndefined();
  });
});

import { describe, expect, it } from 'vitest';
import { buildGraphLinks } from '../../../../src/webview/components/graph/model/link/build';

describe('graph/model/link/build', () => {
  it('marks combined reverse edges as bidirectional links', () => {
    const links = buildGraphLinks(
      [
        { id: 'a.ts->b.ts', from: 'a.ts', to: 'b.ts' , kind: 'import', sources: [] },
        { id: 'b.ts->a.ts', from: 'b.ts', to: 'a.ts' , kind: 'import', sources: [] },
      ],
      'combined'
    );

    expect(links).toEqual([
      expect.objectContaining({
        id: 'a.ts<->b.ts#import',
        source: 'a.ts',
        target: 'b.ts',
        bidirectional: true,
        baseColor: '#60a5fa',
      }),
    ]);
  });

  it('computes curvature for overlapping non-bidirectional links', () => {
    const links = buildGraphLinks(
      [
        { id: 'edge-1', from: 'a.ts', to: 'b.ts' , kind: 'import', sources: [] },
        { id: 'edge-2', from: 'a.ts', to: 'b.ts' , kind: 'import', sources: [] },
      ],
      'separate'
    );

    expect(links).toEqual([
      expect.objectContaining({ id: 'edge-1', curvature: -0.5, bidirectional: false }),
      expect.objectContaining({ id: 'edge-2', curvature: 0.5, bidirectional: false }),
    ]);
  });

  it('keeps different edge kinds straight when they share the same nodes', () => {
    const links = buildGraphLinks(
      [
        { id: 'edge-1', from: 'a.ts', to: 'b.ts' , kind: 'import', sources: [] },
        { id: 'edge-2', from: 'a.ts', to: 'b.ts' , kind: 'call', sources: [] },
      ],
      'separate'
    );

    expect(links).toEqual([
      expect.objectContaining({ id: 'edge-1', bidirectional: false }),
      expect.objectContaining({ id: 'edge-2', bidirectional: false }),
    ]);
    expect(links[0]).not.toHaveProperty('curvature');
    expect(links[1]).not.toHaveProperty('curvature');
  });

  it('normalizes explicit bidirectional flags when separate mode forces one-way links', () => {
    const links = buildGraphLinks(
      [
        {
          id: 'edge-1',
          from: 'a.ts',
          to: 'b.ts',
          kind: 'import',
          sources: [],
        },
      ],
      'separate'
    );

    expect(links).toEqual([
      expect.objectContaining({
        id: 'edge-1',
        bidirectional: false,
        baseColor: undefined,
      }),
    ]);
  });
});

import { describe, it, expect } from 'vitest';
import { buildGraphNodes } from '../../../../src/webview/components/graph/model/node/build';
import { FAVORITE_BORDER_COLOR } from '../../../../src/webview/components/graph/model/node/display';

describe('buildGraphNodes (mutation targets)', () => {
  it('applies dark theme border color for focused node', () => {
    const nodes = buildGraphNodes({
      nodes: [{ id: 'focus.ts', label: 'focus.ts', color: '#80c0ff', depthLevel: 0 }],
      edges: [],
      nodeSizes: new Map([['focus.ts', 16]]),
      theme: 'dark',
      favorites: new Set(),
      timelineActive: false,
    });

    const focusNode = nodes.find(n => n.id === 'focus.ts')!;
    expect(focusNode.borderColor).toBe('#60a5fa');
    expect(focusNode.borderWidth).toBe(4);
  });

  it('applies light theme border color for focused node', () => {
    const nodes = buildGraphNodes({
      nodes: [{ id: 'focus.ts', label: 'focus.ts', color: '#80c0ff', depthLevel: 0 }],
      edges: [],
      nodeSizes: new Map([['focus.ts', 16]]),
      theme: 'light',
      favorites: new Set(),
      timelineActive: false,
    });

    expect(nodes[0].borderColor).toBe('#2563eb');
  });

  it('uses FAVORITE_BORDER_COLOR for non-focused favorite node', () => {
    const nodes = buildGraphNodes({
      nodes: [{ id: 'fav.ts', label: 'fav.ts', color: '#80c0ff' }],
      edges: [],
      nodeSizes: new Map([['fav.ts', 16]]),
      theme: 'dark',
      favorites: new Set(['fav.ts']),
      timelineActive: false,
    });

    expect(nodes[0].borderColor).toBe(FAVORITE_BORDER_COLOR);
    expect(nodes[0].borderWidth).toBe(3);
    expect(nodes[0].isFavorite).toBe(true);
  });

  it('uses raw color as border for non-focused, non-favorite node', () => {
    const nodes = buildGraphNodes({
      nodes: [{ id: 'plain.ts', label: 'plain.ts', color: '#93C5FD' }],
      edges: [],
      nodeSizes: new Map([['plain.ts', 16]]),
      theme: 'dark',
      favorites: new Set(),
      timelineActive: false,
    });

    expect(nodes[0].borderColor).toBe('#93C5FD');
    expect(nodes[0].borderWidth).toBe(2);
  });

  it('uses default node size when nodeSizes map has no entry', () => {
    const nodes = buildGraphNodes({
      nodes: [{ id: 'missing.ts', label: 'missing.ts', color: '#93C5FD' }],
      edges: [],
      nodeSizes: new Map(),
      theme: 'dark',
      favorites: new Set(),
      timelineActive: false,
    });

    expect(nodes[0].size).toBe(16);
  });

  it('does not use previous positions when timeline is not active', () => {
    const nodes = buildGraphNodes({
      nodes: [{ id: 'a.ts', label: 'a.ts', color: '#93C5FD' }],
      edges: [],
      nodeSizes: new Map([['a.ts', 16]]),
      theme: 'dark',
      favorites: new Set(),
      timelineActive: false,
      previousNodes: [{ id: 'a.ts', x: 100, y: 200 }],
    });

    expect(nodes[0].x).toBeUndefined();
    expect(nodes[0].y).toBeUndefined();
  });

  it('uses previous positions when timeline is active', () => {
    const nodes = buildGraphNodes({
      nodes: [{ id: 'a.ts', label: 'a.ts', color: '#93C5FD' }],
      edges: [],
      nodeSizes: new Map([['a.ts', 16]]),
      theme: 'dark',
      favorites: new Set(),
      timelineActive: true,
      previousNodes: [{ id: 'a.ts', x: 100, y: 200 }],
    });

    expect(nodes[0].x).toBe(100);
    expect(nodes[0].y).toBe(200);
  });

  it('preserves node x from source node if set', () => {
    const nodes = buildGraphNodes({
      nodes: [{ id: 'a.ts', label: 'a.ts', color: '#93C5FD', x: 50, y: 60 } as never],
      edges: [],
      nodeSizes: new Map([['a.ts', 16]]),
      theme: 'dark',
      favorites: new Set(),
      timelineActive: false,
    });

    expect(nodes[0].x).toBe(50);
    expect(nodes[0].y).toBe(60);
  });
});

