import { describe, expect, it } from 'vitest';
import { DEFAULT_DIRECTION_COLOR } from '../../../../src/shared/fileColors';
import {
  DEFAULT_NODE_SIZE,
  FAVORITE_BORDER_COLOR,
  getDepthOpacity,
  getDepthSizeMultiplier,
  getNodeType,
  resolveDirectionColor,
} from '../../../../src/webview/components/graph/model/node/display';

describe('graph/model/node/display', () => {
  it('exports the public sizing and favorite border constants', () => {
    expect(DEFAULT_NODE_SIZE).toBe(16);
    expect(FAVORITE_BORDER_COLOR).toBe('#EAB308');
  });

  it('keeps valid direction colors', () => {
    expect(resolveDirectionColor('#123ABC')).toBe('#123ABC');
  });

  it('falls back to the default direction color for invalid colors', () => {
    expect(resolveDirectionColor('blue')).toBe(DEFAULT_DIRECTION_COLOR);
  });

  it('returns lower opacity for deeper nodes', () => {
    expect(getDepthOpacity(undefined)).toBe(1);
    expect(getDepthOpacity(0)).toBe(1);
    expect(getDepthOpacity(2)).toBe(0.7);
    expect(getDepthOpacity(10)).toBe(0.4);
  });

  it('increases the size multiplier only for focused nodes', () => {
    expect(getDepthSizeMultiplier(undefined)).toBe(1);
    expect(getDepthSizeMultiplier(0)).toBe(1.3);
    expect(getDepthSizeMultiplier(2)).toBe(1);
  });

  it('returns a wildcard node type for files without a usable extension', () => {
    expect(getNodeType('README')).toBe('*');
    expect(getNodeType('folder/file.')).toBe('*');
  });

  it('normalizes node types to lower-case extensions', () => {
    expect(getNodeType('Folder/App.TSX')).toBe('.tsx');
  });
});

import { describe, it, expect } from 'vitest';
import {
  assignSelfLoopCurvature,
  assignParallelCurvature,
} from '../../../../src/webview/components/graph/model/link/assignment';
import type { CurvatureLink } from '../../../../src/webview/components/graph/model/link/curvature';

describe('assignSelfLoopCurvature', () => {
  it('assigns curvature 1 to a single self-loop', () => {
    const groups: Record<string, CurvatureLink[]> = {
      'A_A': [{ source: 'A', target: 'A' }],
    };
    assignSelfLoopCurvature(groups, 0.5);

    expect(groups['A_A'][0].curvature).toBe(1);
  });

  it('spreads curvature from curvatureMinMax to 1 for multiple self-loops', () => {
    const groups: Record<string, CurvatureLink[]> = {
      'A_A': [
        { source: 'A', target: 'A' },
        { source: 'A', target: 'A' },
      ],
    };
    assignSelfLoopCurvature(groups, 0.5);

    expect(groups['A_A'][0].curvature).toBe(0.5);
    expect(groups['A_A'][1].curvature).toBe(1);
  });

  it('distributes curvature evenly for three self-loops', () => {
    const groups: Record<string, CurvatureLink[]> = {
      'A_A': [
        { source: 'A', target: 'A' },
        { source: 'A', target: 'A' },
        { source: 'A', target: 'A' },
      ],
    };
    assignSelfLoopCurvature(groups, 0.5);

    expect(groups['A_A'][0].curvature).toBe(0.5);
    expect(groups['A_A'][1].curvature).toBeCloseTo(0.75);
    expect(groups['A_A'][2].curvature).toBe(1);
  });

  it('handles empty groups record', () => {
    const groups: Record<string, CurvatureLink[]> = {};
    assignSelfLoopCurvature(groups, 0.5);
    expect(Object.keys(groups)).toHaveLength(0);
  });
});

describe('assignParallelCurvature', () => {
  it('skips groups with only one link', () => {
    const groups: Record<string, CurvatureLink[]> = {
      'A_B': [{ source: 'A', target: 'B' }],
    };
    assignParallelCurvature(groups, 0.5);

    expect(groups['A_B'][0].curvature).toBeUndefined();
  });

  it('assigns symmetric curvature for two parallel links in same direction', () => {
    const groups: Record<string, CurvatureLink[]> = {
      'A_B': [
        { source: 'A', target: 'B' },
        { source: 'A', target: 'B' },
      ],
    };
    assignParallelCurvature(groups, 0.5);

    expect(groups['A_B'][0].curvature).toBe(-0.5);
    expect(groups['A_B'][1].curvature).toBe(0.5);
  });

  it('negates curvature when link sources differ from the last link source', () => {
    const groups: Record<string, CurvatureLink[]> = {
      'A_B': [
        { source: 'B', target: 'A' },
        { source: 'A', target: 'B' },
      ],
    };
    assignParallelCurvature(groups, 0.5);

    // First link source is 'B', last link source is 'A', they differ
    // So first link curvature is negated: -(-0.5) = 0.5
    expect(groups['A_B'][0].curvature).toBe(0.5);
    expect(groups['A_B'][1].curvature).toBe(0.5);
  });

  it('distributes curvature evenly across three parallel links', () => {
    const groups: Record<string, CurvatureLink[]> = {
      'A_B': [
        { source: 'A', target: 'B' },
        { source: 'A', target: 'B' },
        { source: 'A', target: 'B' },
      ],
    };
    assignParallelCurvature(groups, 0.5);

    expect(groups['A_B'][0].curvature).toBe(-0.5);
    expect(groups['A_B'][1].curvature).toBeCloseTo(0);
    expect(groups['A_B'][2].curvature).toBe(0.5);
  });

  it('handles empty groups record', () => {
    const groups: Record<string, CurvatureLink[]> = {};
    assignParallelCurvature(groups, 0.5);
    expect(Object.keys(groups)).toHaveLength(0);
  });

  it('handles object-style source references for comparison', () => {
    const groups: Record<string, CurvatureLink[]> = {
      'A_B': [
        { source: { id: 'B' }, target: { id: 'A' } },
        { source: { id: 'A' }, target: { id: 'B' } },
      ],
    };
    assignParallelCurvature(groups, 0.5);

    // Sources differ: { id: 'B' } vs { id: 'A' }, so first curvature is negated
    expect(groups['A_B'][0].curvature).toBe(0.5);
    expect(groups['A_B'][1].curvature).toBe(0.5);
  });
});

import { describe, it, expect } from 'vitest';
import {
  resolveId,
  groupLinksByNodePair,
} from '../../../../src/webview/components/graph/model/link/grouping';
import type { CurvatureLink } from '../../../../src/webview/components/graph/model/link/curvature';

describe('resolveId', () => {
  it('returns empty string for null', () => {
    expect(resolveId(null as unknown as undefined)).toBe('');
  });

  it('returns empty string for undefined', () => {
    expect(resolveId(undefined)).toBe('');
  });

  it('returns the string as-is for string input', () => {
    expect(resolveId('abc')).toBe('abc');
  });

  it('converts number to string', () => {
    expect(resolveId(42)).toBe('42');
  });

  it('extracts id from object with string id', () => {
    expect(resolveId({ id: 'node-1' })).toBe('node-1');
  });

  it('extracts id from object with numeric id', () => {
    expect(resolveId({ id: 7 })).toBe('7');
  });

  it('returns empty string for object with undefined id', () => {
    expect(resolveId({ id: undefined })).toBe('');
  });

  it('returns empty string for object without id property', () => {
    expect(resolveId({} as { id?: string })).toBe('');
  });
});

describe('groupLinksByNodePair', () => {
  it('returns empty groups for empty input', () => {
    const result = groupLinksByNodePair([]);
    expect(result.selfLoopLinks).toEqual({});
    expect(result.sameNodesLinks).toEqual({});
  });

  it('groups self-loops separately from regular links', () => {
    const links: CurvatureLink[] = [
      { source: 'A', target: 'A' },
      { source: 'A', target: 'B' },
    ];
    const result = groupLinksByNodePair(links);

    expect(Object.keys(result.selfLoopLinks)).toHaveLength(1);
    expect(Object.keys(result.sameNodesLinks)).toHaveLength(1);
  });

  it('uses canonical pair ordering (alphabetical)', () => {
    const links: CurvatureLink[] = [
      { source: 'B', target: 'A' },
      { source: 'A', target: 'B' },
    ];
    const result = groupLinksByNodePair(links);

    expect(Object.keys(result.sameNodesLinks)).toEqual(['A_B']);
    expect(result.sameNodesLinks['A_B']).toHaveLength(2);
  });

  it('sets nodePairId on each link', () => {
    const links: CurvatureLink[] = [
      { source: 'X', target: 'Y' },
    ];
    groupLinksByNodePair(links);
    expect(links[0].nodePairId).toBe('X_Y');
  });

  it('appends curvature group id when present', () => {
    const links: CurvatureLink[] = [
      { source: 'X', target: 'Y', curvatureGroupId: 'call' },
    ];

    groupLinksByNodePair(links);

    expect(links[0].nodePairId).toBe('X_Y_call');
  });

  it('groups multiple self-loops by the same node', () => {
    const links: CurvatureLink[] = [
      { source: 'A', target: 'A' },
      { source: 'A', target: 'A' },
    ];
    const result = groupLinksByNodePair(links);

    expect(result.selfLoopLinks['A_A']).toHaveLength(2);
  });

  it('handles object-style node references', () => {
    const links: CurvatureLink[] = [
      { source: { id: 'A' }, target: { id: 'B' } },
    ];
    const result = groupLinksByNodePair(links);

    expect(result.sameNodesLinks['A_B']).toHaveLength(1);
  });
});

import { describe, expect, it } from 'vitest';
import { computeFileSizeSizes } from '../../../../src/webview/components/graph/model/sizing/fileSize';

describe('graph/model/sizing/fileSize', () => {
  it('returns defaults when every node has a zero file size', () => {
    const sizes = computeFileSizeSizes([
      { id: 'a', label: 'a', color: '#fff', fileSize: 0 },
      { id: 'b', label: 'b', color: '#fff' },
    ] as never);

    expect(sizes.get('a')).toBe(16);
    expect(sizes.get('b')).toBe(16);
  });

  it('scales positive sizes logarithmically and keeps empty sizes at the minimum', () => {
    const sizes = computeFileSizeSizes([
      { id: 'zero', label: 'zero', color: '#fff', fileSize: 0 },
      { id: 'small', label: 'small', color: '#fff', fileSize: 9 },
      { id: 'large', label: 'large', color: '#fff', fileSize: 9999 },
    ] as never);

    expect(sizes.get('zero')).toBe(10);
    expect(sizes.get('small')).toBeGreaterThan(8);
    expect(sizes.get('large')).toBe(40);
  });
});

import { describe, it, expect } from 'vitest';
import { seedTimelinePositions } from '../../../../src/webview/components/graph/model/timelinePositionSeeding';
import type { FGNode } from '../../../../src/webview/components/graph/model/build';

function makeNode(id: string, x?: number, y?: number): FGNode {
  return { id, label: id, size: 16, color: '#93C5FD', borderColor: '#93C5FD', borderWidth: 2, baseOpacity: 1, isFavorite: false, x, y } as FGNode;
}

describe('seedTimelinePositions (mutation kill tests)', () => {
  /**
   * Kill L15:7 ConditionalExpression: false — mutant replaces
   *   `if (!previousPositions || previousPositions.size === 0) return;`
   * with `if (false) return;` for the !previousPositions part.
   * A non-null map with entries should NOT trigger the early return,
   * and seeding should actually happen.
   */
  it('seeds positions when previousPositions is non-null and non-empty', () => {
    const anchor = makeNode('anchor.ts', 100, 200);
    const newNode = makeNode('new.ts');
    const previousPositions = new Map([['anchor.ts', { x: 100, y: 200 }]]);

    seedTimelinePositions(
      [anchor, newNode],
      [{ id: 'anchor.ts->new.ts', from: 'anchor.ts', to: 'new.ts' , kind: 'import', sources: [] }],
      previousPositions,
      () => 0.5
    );

    // If the guard is bypassed (mutant: false), a null map would crash.
    // But more importantly, with a valid map, seeding must occur.
    expect(newNode.x).toBe(100);
    expect(newNode.y).toBe(200);
  });

  /**
   * Kill L15:29 ConditionalExpression: false — mutant replaces
   *   `previousPositions.size === 0` with `false`.
   * When previousPositions is non-null but empty (size === 0),
   * the function should return early and NOT seed anything.
   * If the mutant turns `size === 0` to false, it will try to
   * process nodes even with an empty map.
   */
  it('returns early without seeding when previousPositions is non-null but empty', () => {
    const newNode = makeNode('new.ts');
    const anchor = makeNode('anchor.ts', 100, 200);
    const emptyMap = new Map<string, { x: number | undefined; y: number | undefined }>();

    seedTimelinePositions(
      [anchor, newNode],
      [{ id: 'anchor.ts->new.ts', from: 'anchor.ts', to: 'new.ts' , kind: 'import', sources: [] }],
      emptyMap,
      () => 0.5
    );

    // With an empty map, even though anchor has coords, the function
    // should return before processing. newNode should remain unseeded.
    expect(newNode.x).toBeUndefined();
    expect(newNode.y).toBeUndefined();
  });

  /**
   * Kill L20:9 ConditionalExpression: false (replaces `node.x !== undefined`)
   * and L20:33 ConditionalExpression: false (replaces `node.y !== undefined`).
   * If either side is replaced with false, a node that has BOTH x and y
   * already set would NOT be skipped and would get overwritten.
   */
  it('preserves both coordinates of an already-positioned node', () => {
    const existing = makeNode('existing.ts', 42, 84);
    const anchor = makeNode('anchor.ts', 100, 200);
    const previousPositions = new Map([['anchor.ts', { x: 100, y: 200 }]]);

    seedTimelinePositions(
      [existing, anchor],
      [{ id: 'existing.ts->anchor.ts', from: 'existing.ts', to: 'anchor.ts' , kind: 'import', sources: [] }],
      previousPositions,
      () => 0.75
    );

    expect(existing.x).toBe(42);
    expect(existing.y).toBe(84);
  });

  /**
   * Kill L20:9 LogicalOperator mutation — changes `||` to `&&`.
   * With `&&`, a node that has x defined but y undefined would NOT be
   * skipped (because `true && false === false`), and would get seeded.
   * The correct behavior: skip if EITHER x or y is defined.
   */
  it('skips node when only x is defined (logical OR not AND)', () => {
    const nodeWithX = makeNode('partial.ts', 77, undefined);
    const anchor = makeNode('anchor.ts', 100, 200);
    const previousPositions = new Map([['anchor.ts', { x: 100, y: 200 }]]);

    seedTimelinePositions(
      [nodeWithX, anchor],
      [{ id: 'partial.ts->anchor.ts', from: 'partial.ts', to: 'anchor.ts' , kind: 'import', sources: [] }],
      previousPositions,
      () => 0.75
    );

    // Should be skipped because x is defined
    expect(nodeWithX.x).toBe(77);
    expect(nodeWithX.y).toBeUndefined();
  });

  /**
   * Kill L22:42 ConditionalExpression: true — mutant replaces
   *   `candidate.to === node.id` with `true`.
   * This means edges.find would match ANY edge, even ones not connected
   * to the node. We test with a node that has NO matching edges.
   */
  it('does not seed a node when no edge connects to it', () => {
    const isolated = makeNode('isolated.ts');
    const anchor = makeNode('anchor.ts', 100, 200);
    const previousPositions = new Map([['anchor.ts', { x: 100, y: 200 }]]);

    seedTimelinePositions(
      [isolated, anchor],
      // Edge between OTHER nodes, not involving 'isolated.ts'
      [{ id: 'other.ts->anchor.ts', from: 'other.ts', to: 'anchor.ts' , kind: 'import', sources: [] }],
      previousPositions,
      () => 0.75
    );

    expect(isolated.x).toBeUndefined();
    expect(isolated.y).toBeUndefined();
  });

  /**
   * Kill L27:38 OptionalChaining mutation — removes the `?.` on `neighbor?.y`.
   * If neighbor is undefined (not in nodePositionMap), accessing `.y`
   * without optional chaining would throw. We need a scenario where
   * the neighbor ID from the edge is NOT in the nodes array.
   */
  it('skips seeding when the neighbor node is not in the nodes array', () => {
    const newNode = makeNode('new.ts');
    const previousPositions = new Map([['ghost.ts', { x: 100, y: 200 }]]);

    seedTimelinePositions(
      [newNode], // ghost.ts is NOT in nodes
      [{ id: 'new.ts->ghost.ts', from: 'new.ts', to: 'ghost.ts' , kind: 'import', sources: [] }],
      previousPositions,
      () => 0.75
    );

    // neighbor = nodePositionMap.get('ghost.ts') => undefined
    // Without optional chaining, this would throw
    expect(newNode.x).toBeUndefined();
    expect(newNode.y).toBeUndefined();
  });

  /**
   * Additional test for L27 — verify that when neighbor exists but has
   * undefined x, seeding is skipped (tests the `neighbor?.x === undefined` branch).
   */
  it('skips seeding when the neighbor exists but has undefined x', () => {
    const neighbor = makeNode('neighbor.ts', undefined, 200);
    const newNode = makeNode('new.ts');
    const previousPositions = new Map([['neighbor.ts', { x: undefined, y: 200 }]]);

    seedTimelinePositions(
      [newNode, neighbor],
      [{ id: 'new.ts->neighbor.ts', from: 'new.ts', to: 'neighbor.ts' , kind: 'import', sources: [] }],
      previousPositions,
      () => 0.5
    );

    expect(newNode.x).toBeUndefined();
    expect(newNode.y).toBeUndefined();
  });
});

import { describe, expect, it } from 'vitest';
import { processEdges } from '../../../../src/webview/components/graph/model/edgeProcessing';

describe('graph/model/edgeProcessing', () => {
  it('combines reverse edges into one bidirectional edge in combined mode', () => {
    expect(
      processEdges(
        [
          { id: 'b.ts->a.ts', from: 'b.ts', to: 'a.ts' , kind: 'import', sources: [] },
          { id: 'a.ts->b.ts', from: 'a.ts', to: 'b.ts' , kind: 'import', sources: [] },
        ],
        'combined'
      )
    ).toEqual([
      {
        id: 'a.ts<->b.ts#import',
        from: 'a.ts',
        to: 'b.ts',
        kind: 'import',
        sources: [],
        bidirectional: true,
      },
    ]);
  });

  it('keeps each edge separate in separate mode', () => {
    expect(
      processEdges(
        [
          { id: 'a.ts->b.ts', from: 'a.ts', to: 'b.ts' , kind: 'import', sources: [] },
          { id: 'b.ts->a.ts', from: 'b.ts', to: 'a.ts' , kind: 'import', sources: [] },
        ],
        'separate'
      )
    ).toEqual([
      {
        id: 'a.ts->b.ts',
        from: 'a.ts',
        to: 'b.ts',
        kind: 'import',
        sources: [],
        bidirectional: false,
      },
      {
        id: 'b.ts->a.ts',
        from: 'b.ts',
        to: 'a.ts',
        kind: 'import',
        sources: [],
        bidirectional: false,
      },
    ]);
  });

  it('skips duplicate reverse pairs once they have been combined', () => {
    expect(
      processEdges(
        [
          { id: 'a.ts->b.ts#import', from: 'a.ts', to: 'b.ts' , kind: 'import', sources: [] },
          { id: 'b.ts->a.ts#import', from: 'b.ts', to: 'a.ts' , kind: 'import', sources: [] },
          { id: 'b.ts->a.ts#import:dynamic', from: 'b.ts', to: 'a.ts' , kind: 'import', sources: [] },
          { id: 'b.ts->c.ts#import', from: 'b.ts', to: 'c.ts' , kind: 'import', sources: [] },
        ],
        'combined'
      )
    ).toEqual([
      {
        id: 'a.ts<->b.ts#import',
        from: 'a.ts',
        to: 'b.ts',
        kind: 'import',
        sources: [],
        bidirectional: true,
      },
      {
        id: 'b.ts->a.ts#import:dynamic',
        from: 'b.ts',
        to: 'a.ts',
        kind: 'import',
        sources: [],
        bidirectional: false,
      },
      {
        id: 'b.ts->c.ts#import',
        from: 'b.ts',
        to: 'c.ts',
        kind: 'import',
        sources: [],
        bidirectional: false,
      },
    ]);
  });
});

import { describe, expect, it } from 'vitest';
import { calculateNodeSizes, toD3Repel } from '../../../../src/webview/components/graph/model/node/sizing';

describe('graph/model/node/sizing', () => {
  it('maps normalized repel force to the d3 force range', () => {
    expect(Object.is(toD3Repel(0), -0)).toBe(true);
    expect(toD3Repel(10)).toBe(-250);
    expect(toD3Repel(20)).toBe(-500);
  });

  it('uses the default size for uniform node sizing', () => {
    const sizes = calculateNodeSizes(
      [
        { id: 'a.ts', label: 'a.ts', color: '#93C5FD' },
        { id: 'b.ts', label: 'b.ts', color: '#67E8F9' },
      ],
      [],
      'uniform'
    );

    expect(sizes.get('a.ts')).toBe(16);
    expect(sizes.get('b.ts')).toBe(16);
  });

  it('scales connection-based node sizes by edge count', () => {
    const sizes = calculateNodeSizes(
      [
        { id: 'hub.ts', label: 'hub.ts', color: '#93C5FD' },
        { id: 'leaf-a.ts', label: 'leaf-a.ts', color: '#67E8F9' },
        { id: 'leaf-b.ts', label: 'leaf-b.ts', color: '#67E8F9' },
      ],
      [
        { from: 'hub.ts', to: 'leaf-a.ts' },
        { from: 'hub.ts', to: 'leaf-b.ts' },
      ],
      'connections'
    );

    expect(sizes.get('hub.ts')).toBe(40);
    expect(sizes.get('leaf-a.ts')).toBe(25);
    expect(sizes.get('leaf-b.ts')).toBe(25);
  });

  it('scales access-count node sizes from the observed range', () => {
    const sizes = calculateNodeSizes(
      [
        { id: 'small.ts', label: 'small.ts', color: '#93C5FD', accessCount: 1 },
        { id: 'medium.ts', label: 'medium.ts', color: '#67E8F9', accessCount: 2 },
        { id: 'large.ts', label: 'large.ts', color: '#38BDF8', accessCount: 5 },
      ],
      [],
      'access-count'
    );

    expect(sizes.get('small.ts')).toBe(16);
    expect(sizes.get('medium.ts')).toBe(22);
    expect(sizes.get('large.ts')).toBe(40);
  });

  it('returns default sizes when file-size mode has no positive file sizes', () => {
    const sizes = calculateNodeSizes(
      [
        { id: 'empty.ts', label: 'empty.ts', color: '#93C5FD' },
        { id: 'zero.ts', label: 'zero.ts', color: '#67E8F9', fileSize: 0 },
      ],
      [],
      'file-size'
    );

    expect(sizes.get('empty.ts')).toBe(16);
    expect(sizes.get('zero.ts')).toBe(16);
  });

  it('uses log scaling for positive file sizes and keeps zero-byte files at the minimum', () => {
    const sizes = calculateNodeSizes(
      [
        { id: 'zero.ts', label: 'zero.ts', color: '#93C5FD', fileSize: 0 },
        { id: 'small.ts', label: 'small.ts', color: '#67E8F9', fileSize: 99 },
        { id: 'large.ts', label: 'large.ts', color: '#38BDF8', fileSize: 9999 },
      ],
      [],
      'file-size'
    );

    expect(sizes.get('zero.ts')).toBe(10);
    expect(sizes.get('small.ts')).toBe(10);
    expect(sizes.get('large.ts')).toBe(40);
  });
});

import { describe, it, expect } from 'vitest';
import {
  resolveDirectionColor,
  getDepthOpacity,
  getDepthSizeMultiplier,
  getNodeType,
} from '../../../../src/webview/components/graph/model/node/display';
import { DEFAULT_DIRECTION_COLOR } from '../../../../src/shared/fileColors';

describe('nodeDisplay (mutation targets)', () => {
  describe('resolveDirectionColor', () => {
    it('accepts valid 6-digit hex color with uppercase', () => {
      expect(resolveDirectionColor('#AABBCC')).toBe('#AABBCC');
    });

    it('accepts valid 6-digit hex color with lowercase', () => {
      expect(resolveDirectionColor('#aabbcc')).toBe('#aabbcc');
    });

    it('rejects 3-digit hex shorthand', () => {
      expect(resolveDirectionColor('#abc')).toBe(DEFAULT_DIRECTION_COLOR);
    });

    it('rejects empty string', () => {
      expect(resolveDirectionColor('')).toBe(DEFAULT_DIRECTION_COLOR);
    });

    it('rejects color name', () => {
      expect(resolveDirectionColor('red')).toBe(DEFAULT_DIRECTION_COLOR);
    });

    it('rejects hex without hash', () => {
      expect(resolveDirectionColor('AABBCC')).toBe(DEFAULT_DIRECTION_COLOR);
    });
  });

  describe('getDepthOpacity', () => {
    it('returns 1.0 for undefined depth', () => {
      expect(getDepthOpacity(undefined)).toBe(1.0);
    });

    it('returns 1.0 for depth 0 (focused)', () => {
      expect(getDepthOpacity(0)).toBe(1.0);
    });

    it('returns 0.85 for depth 1', () => {
      expect(getDepthOpacity(1)).toBeCloseTo(0.85);
    });

    it('returns 0.7 for depth 2', () => {
      expect(getDepthOpacity(2)).toBeCloseTo(0.7);
    });

    it('clamps to 0.4 for very deep nodes', () => {
      expect(getDepthOpacity(100)).toBe(0.4);
    });

    it('returns exactly 0.4 at depth 4', () => {
      expect(getDepthOpacity(4)).toBeCloseTo(0.4);
    });
  });

  describe('getDepthSizeMultiplier', () => {
    it('returns 1.0 for undefined depth', () => {
      expect(getDepthSizeMultiplier(undefined)).toBe(1.0);
    });

    it('returns 1.3 for focused node (depth 0)', () => {
      expect(getDepthSizeMultiplier(0)).toBe(1.3);
    });

    it('returns 1.0 for depth 1', () => {
      expect(getDepthSizeMultiplier(1)).toBe(1.0);
    });

    it('returns 1.0 for depth 5', () => {
      expect(getDepthSizeMultiplier(5)).toBe(1.0);
    });
  });

  describe('getNodeType', () => {
    it('returns lower-case extension for normal file', () => {
      expect(getNodeType('src/App.tsx')).toBe('.tsx');
    });

    it('returns wildcard for file without extension', () => {
      expect(getNodeType('Makefile')).toBe('*');
    });

    it('returns wildcard for file ending with dot', () => {
      expect(getNodeType('file.')).toBe('*');
    });

    it('returns the last extension for multi-dot filenames', () => {
      expect(getNodeType('module.test.ts')).toBe('.ts');
    });

    it('handles deeply nested paths', () => {
      expect(getNodeType('a/b/c/d/file.go')).toBe('.go');
    });
  });
});

