import { describe, it, expect } from 'vitest';
import { seedTimelinePositions } from '../../../../src/webview/components/graph/model/timelinePositionSeeding';
import type { FGNode } from '../../../../src/webview/components/graph/model/build';

function makeNode(id: string, x?: number, y?: number): FGNode {
  return { id, label: id, size: 16, color: '#93C5FD', borderColor: '#93C5FD', borderWidth: 2, baseOpacity: 1, isFavorite: false, x, y } as FGNode;
}

describe('graph/model/timelinePositionSeeding', () => {
  it('does nothing when previousPositions is null', () => {
    const node = makeNode('a.ts');
    seedTimelinePositions([node], [], null, Math.random);
    expect(node.x).toBeUndefined();
    expect(node.y).toBeUndefined();
  });

  it('does nothing when previousPositions is empty', () => {
    const node = makeNode('a.ts');
    seedTimelinePositions([node], [], new Map(), Math.random);
    expect(node.x).toBeUndefined();
    expect(node.y).toBeUndefined();
  });

  it('skips nodes that already have a position', () => {
    const node = makeNode('a.ts', 50, 60);
    const previousPositions = new Map([['anchor.ts', { x: 100, y: 200 }]]);
    seedTimelinePositions(
      [node],
      [{ id: 'a.ts->anchor.ts', from: 'a.ts', to: 'anchor.ts' , kind: 'import', sources: [] }],
      previousPositions,
      () => 0.75
    );
    expect(node.x).toBe(50);
    expect(node.y).toBe(60);
  });

  it('seeds a new node near a connected neighbor with a known position', () => {
    const anchor = makeNode('anchor.ts', 100, 200);
    const newNode = makeNode('new.ts');
    const previousPositions = new Map([['anchor.ts', { x: 100, y: 200 }]]);

    seedTimelinePositions(
      [anchor, newNode],
      [{ id: 'anchor.ts->new.ts', from: 'anchor.ts', to: 'new.ts' , kind: 'import', sources: [] }],
      previousPositions,
      () => 0.75
    );

    expect(newNode.x).toBe(110);
    expect(newNode.y).toBe(210);
  });

  it('skips a node when its neighbor has no recorded position', () => {
    const orphan = makeNode('orphan.ts');
    const previousPositions = new Map([['anchor.ts', { x: undefined, y: undefined }]]);

    seedTimelinePositions(
      [orphan],
      [{ id: 'orphan.ts->anchor.ts', from: 'orphan.ts', to: 'anchor.ts' , kind: 'import', sources: [] }],
      previousPositions,
      () => 0.75
    );

    expect(orphan.x).toBeUndefined();
    expect(orphan.y).toBeUndefined();
  });

  it('skips a node that has no connected edges', () => {
    const solo = makeNode('solo.ts');
    const previousPositions = new Map([['anchor.ts', { x: 100, y: 200 }]]);

    seedTimelinePositions([solo], [], previousPositions, () => 0.75);

    expect(solo.x).toBeUndefined();
    expect(solo.y).toBeUndefined();
  });
});

import { describe, it, expect } from 'vitest';
import {
  MIN_NODE_SIZE,
  MAX_NODE_SIZE,
  computeUniformSizes,
  computeConnectionSizes,
} from '../../../../src/webview/components/graph/model/sizing/calculations';

describe('sizingCalculations constants', () => {
  it('exports MIN_NODE_SIZE as 10', () => {
    expect(MIN_NODE_SIZE).toBe(10);
  });

  it('exports MAX_NODE_SIZE as 40', () => {
    expect(MAX_NODE_SIZE).toBe(40);
  });
});

describe('computeUniformSizes', () => {
  it('assigns default size (16) to every node', () => {
    const sizes = computeUniformSizes([
      { id: 'a.ts', label: 'a.ts', color: '#fff' },
      { id: 'b.ts', label: 'b.ts', color: '#fff' },
    ]);
    expect(sizes.get('a.ts')).toBe(16);
    expect(sizes.get('b.ts')).toBe(16);
  });

  it('returns empty map for empty node list', () => {
    expect(computeUniformSizes([]).size).toBe(0);
  });
});

describe('computeConnectionSizes', () => {
  it('assigns minimum size to nodes with no edges', () => {
    const sizes = computeConnectionSizes(
      [{ id: 'solo.ts', label: 'solo.ts', color: '#fff' }],
      []
    );
    expect(sizes.get('solo.ts')).toBe(MIN_NODE_SIZE);
  });

  it('assigns maximum size to the most connected node', () => {
    const sizes = computeConnectionSizes(
      [
        { id: 'hub.ts', label: 'hub.ts', color: '#fff' },
        { id: 'leaf.ts', label: 'leaf.ts', color: '#fff' },
      ],
      [{ from: 'hub.ts', to: 'leaf.ts' }]
    );
    expect(sizes.get('hub.ts')).toBe(MAX_NODE_SIZE);
  });

  it('handles edge nodes not in the node list', () => {
    const sizes = computeConnectionSizes(
      [{ id: 'a.ts', label: 'a.ts', color: '#fff' }],
      [{ from: 'a.ts', to: 'missing.ts' }]
    );
    // a.ts has 1 connection, but missing.ts is counted too even without a node entry
    expect(sizes.get('a.ts')).toBeDefined();
  });

  it('counts each edge for both from and to nodes', () => {
    const sizes = computeConnectionSizes(
      [
        { id: 'a.ts', label: 'a.ts', color: '#fff' },
        { id: 'b.ts', label: 'b.ts', color: '#fff' },
        { id: 'c.ts', label: 'c.ts', color: '#fff' },
      ],
      [
        { from: 'a.ts', to: 'b.ts' },
        { from: 'a.ts', to: 'c.ts' },
      ]
    );
    // a: 2 connections (from both), b: 1 (to), c: 1 (to)
    expect(sizes.get('a.ts')).toBe(MAX_NODE_SIZE);
    expect(sizes.get('b.ts')).toBe(sizes.get('c.ts'));
    expect(sizes.get('b.ts')).toBeLessThan(MAX_NODE_SIZE);
  });

  it('produces sizes between MIN_NODE_SIZE and MAX_NODE_SIZE', () => {
    const sizes = computeConnectionSizes(
      [
        { id: 'hub.ts', label: 'hub.ts', color: '#fff' },
        { id: 'leaf.ts', label: 'leaf.ts', color: '#fff' },
      ],
      [
        { from: 'hub.ts', to: 'leaf.ts' },
      ]
    );
    for (const size of sizes.values()) {
      expect(size).toBeGreaterThanOrEqual(MIN_NODE_SIZE);
      expect(size).toBeLessThanOrEqual(MAX_NODE_SIZE);
    }
  });
});

